class Solution {
    private static final int MOD = (int)1e9 + 7;
    public int countNumbers(String l, String r, int b) {
        int res = 0;
        for (int i = (int)l.charAt(0) - '0'; i < 10; i++) {
            res = (res + dp(l.length(), i, b)) % MOD;
        }
        for (int i = (int)r.charAt(0) - '0'; i >= (int)l.charAt(0) - '0'; i--) {
            res = (res - dp(r.length(), i, b) + MOD) % MOD;
        }
        return res;
    }
    private int dp(int len, int x, int b) {
        if (len == 0) return 1;
        int res = 0;
        for (int i = 0; i <= x; i++) {
            res = (res + dp(len - 1, i, b)) % MOD;
        }
        return res;
    }
}
